class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_word = False
        self.word = None

class Solution:
    def findWords(self, board: list[list[str]], words: list[str]) -> list[str]:
        root = TrieNode()
        for word in words:
            node = root
            for char in word:
                if char not in node.children:
                    node.children[char] = TrieNode()
                node = node.children[char]
            node.is_word = True
            node.word = word

        ROWS, COLS = len(board), len(board[0])
        res = []

        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

        def dfs(r, c, parent_node, char_key):
            char = board[r][c]
            curr_node = parent_node.children[char_key]

            if curr_node.is_word:
                res.append(curr_node.word)
                curr_node.is_word = False

            temp_char = board[r][c]
            board[r][c] = '#'

            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if 0 <= nr < ROWS and 0 <= nc < COLS and board[nr][nc] != '#':
                    next_char = board[nr][nc]
                    if next_char in curr_node.children:
                        dfs(nr, nc, curr_node, next_char)

            board[r][c] = temp_char

            if not curr_node.children and not curr_node.is_word:
                del parent_node.children[char_key]

        for r in range(ROWS):
            for c in range(COLS):
                if board[r][c] in root.children:
                    dfs(r, c, root, board[r][c])

        return res
